var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"기관 놈들……! 기어코 반격하려는 건가!","JPN":"機関のやつら……！　どうしても反撃するつもりか！","ENG":"Those Institution bastards...! Trying to fight back, huh?!","TWN":"機關的那些傢伙……！最終還是選擇反擊嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"그림자들을 지원하라! 파편을 빼앗길 수는 없다!","JPN":"シャドウを支援しろ！　破片を奪われるわけにはいかない！","ENG":"Support the Shadows! Don't let them take away the Fragment!","TWN":"支援暗影們！不能讓他們搶走碎片！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_NULL","text":{"KOREA":"크억……!","JPN":"くあっ……！","ENG":"Kuh...!","TWN":"咳呃……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_STING_BIG"},{"id":"L6_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"베네딕트를 찾으라고 보냈더니, 번거로운 일감을 떠맡고 왔군요.","JPN":"ベネディクトを探せと向かわせたのに、厄介な仕事を抱えて帰ってきましたね。","ENG":"I sent you to find Benedict, and you returned with a tedious assignment.","TWN":"派你去找本尼迪克特，結果你卻惹回來一堆麻煩事。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"뭐래, 안경 꼰대. 자기가 만나 보라고 해 놓고서.","JPN":"何言ってんだよ、眼鏡ばばあ。自分で会ってみろって言ったくせに。","ENG":"What are you saying, Specky Snob. You're the one who told me to go see him.","TWN":"你說什麼呢，眼鏡女。明明是你讓我去見他的。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"저 분들…… 시신에서 뭔가 기어나오고 있어요.","JPN":"あの方々……死体から何かが這い出てきますわ。","ENG":"Those people... Something is crawling out from their corpses.","TWN":"那些人……屍體上有東西爬出來。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"맙소사. 넬슨이 만든 오징어 먹물 스파게티랑 빼닮았는데.","JPN":"うわぁ。ネルソンが作ったイカ墨パスタとそっくり。","ENG":"Oof. It looks just like Nelson's squid ink spaghetti!","TWN":"天啊，和尼爾森製作的魷魚墨汁義大利麵一樣。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_NULL","text":{"KOREA":"대체 저것들에게 뭘 먹인 거야? 거짓말하면 엉덩이 맴매해 준다?","JPN":"あれにいったい何を食べさせたんだ？　ウソついたら、お尻ぺんぺん食らわすよ。","ENG":"What in the world did they feed those things? I'm gonna spank you if you lie to me!","TWN":"到底餵那些東西吃了什麼？說謊的話會打屁股喔？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그런 적 없어요, 자매님! 제가 만든 건 좀 더 상냥하다고요!","JPN":"食べさせたことなんかありません、シスター・シンディー！　私が作ったものはもっと優しいのです！","ENG":"That's not true, Sister! The ones I made were friendlier!","TWN":"我沒有，姐妹！我做的更溫柔一些！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"……후우. 이 기회에 정보 기관에게 빚을 지워 둬서 나쁠 건 없죠.","JPN":"……ふう。この際、情報機関に貸しを作っておくのもいいでしょう。","ENG":"*Sigh...* I see no problem with using this opportunity to settle our debts with the intelligence agency.","TWN":"……呼，趁這個機會，還情報部門一個人情也不錯。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"적어도 저들이 철퇴 용병단의 실종 사건 당시 배후에 있던 건 읽어냈습니다.","JPN":"少なくとも彼らが鉄槌傭兵団の失踪事件当時、背後にいたということは読みました。","ENG":"At least, I read that they were responsible for the disappearance of the Mace Mercenary.","TWN":"至少他們在鐵鎚傭兵團失蹤案件當時，查出了幕後兇手。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"방패 용병단, 교전에 협조적으로 응해 주세요.","JPN":"盾傭兵団、交戦に協力してください。","ENG":"Shield Mercenary, please cooperate in combat.","TWN":"盾牌傭兵團，請配合一下交戰。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_STATE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"저 소란은 뭐야? 설마 지원이 도착한 건가?","JPN":"あの騒動は何？　まさか支援が来たのかしら？","ENG":"What's all this commotion? Did their reinforcements arrive?","TWN":"那邊的騷亂是怎麼回事？難道是援軍到了？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"한눈 팔 틈이 있으려나, 최고 단원 씨.","JPN":"よそ見なんてしてる暇があるの？　首席奏者さん。","ENG":"I don't think you have time to worry about that, Ms. Elite Member.","TWN":"你還有閒工夫分心嗎，首席團員。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L25_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"지휘자님, 퇴각해야겠어요. 이대로는 오히려 저희가 고사하게 생겼는걸요.","JPN":"マエストロ、退却しましょう。このままでは、むしろ私たちが枯死してしまいますわ。","ENG":"Chief Conductor, we must retreat. We'll be the ones to die at this rate!","TWN":"指揮家，該撤退了。照這樣下去，對我們反而不利。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"당황해서 우리가 누군지 잊어 버리기라도 한 거야, 셰나?","JPN":"焦って私たちが誰なのか忘れてしまったの？　シェナ。","ENG":"Did you get so disgruntled that you forgot who we were, Shena?","TWN":"因為驚慌你就忘了我們是誰嗎，世娜？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"주위를 잘 살펴 보렴. 숫자만 늘어 봤자 우리에겐 가지고 놀 가축들만 늘어나는 거야.","JPN":"周りをよく見てちょうだい。数が多くなっても、私たちにとっては弄ぶ家畜が増えるだけよ。","ENG":"Look around you. If they increase in number, it simply means we have more toys to play with.","TWN":"你好好看看周圍，就算人數增加，也只是增加了我們可以玩弄的牲畜。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"기회를 잡기만 하면……","JPN":"チャンスさえつかんだら……","ENG":"When our chance comes─","TWN":"只要抓住機會……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"국경 수비대 전원, 조준!","JPN":"全国境守備隊員、照準！","ENG":"Border Guards, aim!","TWN":"國境護衛隊全體隊員，瞄準！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"일제 사격!","JPN":"一斉射撃！","ENG":"FIRE!!","TWN":"一齊射擊！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L41_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"뭐야, 저 시대착오적인 무기는! 피부에 생채기가 날 뻔했잖아!","JPN":"何なの？　あの時代遅れの武器は！　肌に傷がつくところだったわ！","ENG":"What is with them and their primitive weapons?! It almost ripped off my skin!","TWN":"什麼嘛，這種不合時宜的武器！我的皮膚差點被擦傷！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WATT_BORDER_NULL_ARMED","text":{"KOREA":"역시 그 그림자랑 동류인가? 한두 발로는 티도 안 나는데?","JPN":"やっぱあのシャドウと同類か？　一、二発では何の効果もねえな。","ENG":"Are they the same kind as the last Shadow? One or two shots don't seem to affect her.","TWN":"果然跟那個暗影是同類嗎？一兩發子彈完全不起作用？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PITER_BORDER_NULL_ARMED","text":{"KOREA":"투덜거릴 틈 있어요? 어서 장전해요, 와트 씨!","JPN":"文句言ってる暇はありませんよ！　早く装填してください、ワットさん！","ENG":"There's no time to grumble, Mr. Watt! Reload your gun already!","TWN":"你還有時間抱怨嗎？快點裝彈，華特！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PITER_BORDER_NULL_ARMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATT_BORDER_NULL_ARMED","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"으윽……!?","JPN":"ううっ……！？","ENG":"Ngh?!","TWN":"呃呃……！？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"음률이 어긋났어……? 어떻게……!","JPN":"音律がずれた……？　どうやって……！","ENG":"The melody is off...? But how...?!","TWN":"旋律錯了……？怎麼辦……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그 불길한 기운, 중사란 소녀의 말대로 악기에 기생하는 망령이로군.","JPN":"その不吉な力、軍曹という少女から聞いたとおり楽器に寄生する亡霊だな。","ENG":"That ominous energy... So you are the ghost who lives inside instruments just as that Sergeant girl mentioned.","TWN":"那種不祥的氣息，就是少女中士說的寄生在樂器中的鬼魂啊。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"그 빛은…? 네가 왜…!","JPN":"その光は……？　どうしてあなたが……！","ENG":"That light...? But why do you...?!","TWN":"那束光……？你為什麼……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"왕국 남부 국경수비대 소속 지휘대장, 제라드 큐리안.","JPN":"王国南部国境守備隊所属の指揮隊長、ジェラード・キュリアン。","ENG":"Gerard Curian, Commanding Officer of the Southern Border Guards.","TWN":"我是王國南方國境護衛隊的隊長，傑瑞德·庫里安。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"구국의 영웅에게 요청 받아 가세했다.","JPN":"救国の英雄からの要請で加勢した。","ENG":"I am here to respond to the request from the hero who saved the country.","TWN":"我是受救國英雄之邀來的。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"사라진 게 아니라 신체에 융합됐던 거라고? 말도 안 돼…!","JPN":"消えたのではなく、体に融合していたってこと？　あり得ないわ……！","ENG":"It didn't disappear, but was fused into someone's body? Impossible...!","TWN":"不是消失了，而是融合到了身體了？這不可能……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"너희들의 만행은 이미 조국에서 지긋지긋하게 겪었다.","JPN":"貴様らの蛮行はすでに祖国で飽きるほど経験した。","ENG":"We already know about the atrocities you have caused in our homeland.","TWN":"國家已經受夠你們的暴行了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"도망칠 생각은 마라.","JPN":"逃げられると思うな。","ENG":"I will not allow you to flee.","TWN":"你們休想逃走。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"원수를 만들고 돌아다닌 대가를 치를 때 아니려나.","JPN":"敵を作りまくった代償を払う時じゃないかしら。","ENG":"Guess it's time you pay the price for making all those enemies.","TWN":"是時候讓你們為到處樹敵而付出代價了吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"언제까지 모든 일들이 너희들 좋을 대로 돌아갈 줄 알았다면 오산이야.","JPN":"いつまでもすべてがあなたたちの思いどおりに行くと思ったら大間違いよ。","ENG":"You were mistaken if you thought that everything would go as you please.","TWN":"如果你們以為所有事都會如你們所願，那就大錯特錯了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"저건……. 황금가지? 교단의 성유물이 왜?","JPN":"あれは……金の枝？　教団の聖遺物がどうして？","ENG":"That's... The Golden Branch? Why is the Holy Relic of the Order here?","TWN":"那是……金枝？教團的聖遺物為什麼會在你身上？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"초, 총사대장님! 이쪽! 이쪽부터 먼저 상대하자고요!","JPN":"じゅ、銃士隊長！　こっち！　こっちから相手しましょう！","ENG":"G-General Musketeer! Over here! We should deal with the ones over here!","TWN":"隊長！這邊！先解決這邊吧！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"중사, 당신이 저들을 불러들였군요.","JPN":"軍曹、あなたが彼らを呼び入れたのですね。","ENG":"Sergeant, so you are the one who brought them here.","TWN":"中士，是你叫他們來的啊。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"하지만 제 앞에 당당히 나타나고도 무사하실 줄 아셨나요?","JPN":"ですが、私の前に堂々と現れて無事でいられると思ったのですか？","ENG":"But did you think you'd get out unscathed after appearing in front of me?","TWN":"不過你以為出現在我面前，你還能全身而退嗎？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으윽…….","JPN":"ううっ……","ENG":"Ngh...","TWN":"呃嗯……"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지금이에요! 호라이즌 씨!","JPN":"今です！　ホライズンさん！","ENG":"Now! Ms. Horizon!","TWN":"就是現在！地平線！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"큭!?","JPN":"くっ！？","ENG":"Kgh?!","TWN":"咳！？"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOOM_REPEAT"},{"id":"L22_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"뒤에도 눈을 다시지 그러셨습니까, 침식체.","JPN":"後ろにも目をつけた方がよかったのではないですか？　侵食体。","ENG":"No eyes in the back, C.O.?","TWN":"為什麼不看著點後面呢，侵蝕體。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"확실히 이전에 상대했을 때와 비교하면 출력이 낮아졌군요.","JPN":"確かに以前相手した時と比べると出力が落ちましたね。","ENG":"Your power output is definitely lower than our last encounter.","TWN":"和以前交手的時候相比，你的輸出確實下降了。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"시무르그……!","JPN":"シムルグ……！","ENG":"Simurgh...!","TWN":"西摩格……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"늦었습니다. 충격에나 대비하십시오.","JPN":"もう遅いです。衝撃にでも備えてください。","ENG":"Too late. Brace yourself for impact.","TWN":"晚了。準備應對衝擊吧。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"열복사 반경 계산 완료. 광역 섬멸 프로그램.","JPN":"熱放射の半径、計算完了。広域殲滅プログラム。","ENG":"Heat radiation radius calculation completed. Wide Area Annihilation Program.","TWN":"熱輻射半徑計算完畢。範圍殲滅程式。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"제가, 이런 얕은 꾀에 당하리라고 생각하셨다면……!","JPN":"私が、このような浅はかな手にやられると思ったら……！","ENG":"If you thought I would fall for such petty tricks...!","TWN":"如果你以為我會被這種雕蟲小技打倒……！"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_COLD_NULL_NULL","text":{"KOREA":"실행.","JPN":"実行。","ENG":"Execute.","TWN":"執行。"},"stage":{"bg":"PRYDWEN","bgm":"THEMA_SCAENA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_COLD_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};